import json
with open('/home/azureuser/.uipath/maestro/registry.json') as f:
    data = json.load(f)
ext_types = data['static']['extensionTypes']
print(type(ext_types), len(ext_types) if isinstance(ext_types, list) else list(ext_types.keys())[:5])
# find HITL
if isinstance(ext_types, list):
    for e in ext_types:
        if 'HITL' in str(e.get('extensionType','')) or 'HITL' in str(e.get('ExtensionType','')):
            print(json.dumps(e, indent=2))
            break
elif isinstance(ext_types, dict):
    for k,v in ext_types.items():
        if 'HITL' in k:
            print(k, json.dumps(v, indent=2)[:2000])
            break
"

